headStyles:
    * { margin: 0; padding: 0; box-sizing: border-box; }
    :root {
        --navy: #0f2233;
        --navy-deep: #0a1929;
        --navy-light: #132d44;
        --navy-card: rgba(19,45,68,0.5);
        --text-white: #ffffff;
        --text-soft: rgba(255,255,255,0.85);
        --text-dim: rgba(255,255,255,0.6);
        --accent: #73d7ee;
        --action-blue: #004dff;
        --border: rgba(255,255,255,0.08);
        --rainbow: linear-gradient(90deg, #e40303 0%, #ff8c00 17%, #ffed00 33%, #008026 50%, #004dff 67%, #750787 84%, #e40303 100%);
        --transition: all 0.3s ease;
    }

@keyframes prideShimmer {
    0%   { background-position: 0% 50%; }
    100% { background-position: 200% 50%; }
}
@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}

html { scroll-behavior: smooth; }
body { font-family: 'Roboto Slab', Georgia, serif; background-color: var(--navy); color: var(--text-white); line-height: 1.6; overflow-x: hidden; }
a { color: inherit; text-decoration: none; }

/* Hero */
.hero {
    position: relative;
    padding: 5rem 2rem 3rem;
    text-align: center;
    max-width: 900px;
    margin: 0 auto;
    overflow: hidden;
}
.hero::before {
    content: '';
    position: absolute;
    top: -100px;
    left: 50%;
    transform: translateX(-50%);
    width: 600px;
    height: 600px;
    background: radial-gradient(circle, rgba(115,215,238,0.12) 0%, rgba(117,7,135,0.06) 40%, transparent 70%);
    border-radius: 50%;
    pointer-events: none;
    z-index: 0;
}
.hero > * { position: relative; z-index: 1; }
.hero-eyebrow {
    display: inline-flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 1.25rem;
    background: rgba(115,215,238,0.1);
    border: 1px solid rgba(115,215,238,0.3);
    border-radius: 100px;
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 1.5rem;
    animation: fadeInUp 0.6s ease-out;
}
.hero h1 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(2.5rem, 6.5vw, 4rem);
    line-height: 1.05;
    margin-bottom: 1rem;
    font-weight: 900;
    letter-spacing: -1.5px;
    animation: fadeInUp 0.8s ease-out;
}
.hero h1 .rainbow-word {
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 6s linear infinite;
    -webkit-background-clip: text;
    background-clip: text;
    color: transparent;
}
.hero-tagline {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(1rem, 2.2vw, 1.2rem);
    color: var(--text-soft);
    max-width: 620px;
    margin: 0 auto 2rem;
    line-height: 1.55;
    animation: fadeInUp 1s ease-out;
}
.hero-divider {
    width: 100px;
    height: 4px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
    margin: 0 auto;
    border-radius: 2px;
}

/* Section */
.section { max-width: 1100px; margin: 4rem auto; padding: 0 2rem; }
.section-header { text-align: center; max-width: 720px; margin: 0 auto 2.5rem; }
.section-eyebrow {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 3px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 0.75rem;
}
.section-header h2 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: clamp(1.75rem, 4vw, 2.4rem);
    line-height: 1.15;
    margin-bottom: 1rem;
    font-weight: 800;
    letter-spacing: -0.5px;
}
.section-header p { color: var(--text-soft); font-size: 1.05rem; line-height: 1.7; }

/* Format note */
.format-note {
    display: inline-flex;
    flex-wrap: wrap;
    justify-content: center;
    align-items: center;
    gap: 0.4rem 0.9rem;
    padding: 0.6rem 1.1rem;
    margin: 0.75rem auto 0;
    background: rgba(115,215,238,0.08);
    border: 1px solid rgba(115,215,238,0.25);
    border-radius: 100px;
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.78rem;
    color: var(--text-soft);
    letter-spacing: 0.5px;
}
.format-note .pill {
    font-weight: 700;
    color: var(--accent);
    text-transform: uppercase;
    letter-spacing: 1.5px;
    font-size: 0.7rem;
}
.format-note .sep { color: var(--text-dim); }

/* Schedule cards */
.schedule-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1.5rem;
}
@media (max-width: 800px) { .schedule-grid { grid-template-columns: 1fr; } }
.schedule-card .format {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.75rem;
    color: var(--text-dim);
    margin-bottom: 1rem;
    letter-spacing: 0.5px;
}
.schedule-card .format strong { color: var(--accent); font-weight: 700; }

.schedule-card {
    position: relative;
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2rem 1.75rem 1.75rem;
    background: var(--navy-card);
    display: flex;
    flex-direction: column;
    transition: var(--transition);
    overflow: hidden;
}
.schedule-card:hover {
    transform: translateY(-4px);
    border-color: rgba(115,215,238,0.3);
    background: rgba(19,45,68,0.7);
}
.schedule-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.schedule-card.featured {
    border-color: rgba(115,215,238,0.4);
    background: linear-gradient(135deg, rgba(19,45,68,0.7) 0%, rgba(117,7,135,0.18) 100%);
}
.featured-tag {
    position: absolute;
    top: 1rem;
    right: 1rem;
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.6rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--navy);
    background: var(--accent);
    padding: 0.25rem 0.6rem;
    border-radius: 100px;
    font-weight: 800;
}
.duration {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 0.5rem;
}
.schedule-card h3 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.5rem;
    font-weight: 800;
    margin-bottom: 0.75rem;
    letter-spacing: -0.3px;
}
.schedule-card p {
    color: var(--text-soft);
    font-size: 0.95rem;
    line-height: 1.65;
    margin-bottom: 1.25rem;
    flex-grow: 1;
}
.schedule-card ul {
    list-style: none;
    margin-bottom: 1.5rem;
}
.schedule-card ul li {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.85rem;
    color: var(--text-soft);
    padding: 0.35rem 0 0.35rem 1.5rem;
    position: relative;
    line-height: 1.4;
}
.schedule-card ul li::before {
    content: '\2713';
    position: absolute;
    left: 0;
    top: 0.35rem;
    color: var(--accent);
    font-weight: 700;
}
.btn {
    font-family: 'Montserrat', Arial, sans-serif;
    padding: 0.95rem 1.5rem;
    border-radius: 8px;
    font-weight: 700;
    font-size: 0.9rem;
    transition: var(--transition);
    border: none;
    cursor: pointer;
    display: inline-block;
    text-align: center;
    letter-spacing: 1px;
    text-transform: uppercase;
}
.btn-schedule {
    background: var(--action-blue);
    color: #ffffff;
    width: 100%;
}
.btn-schedule:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 24px rgba(0,77,255,0.4);
    background: #0040d9;
}
.btn-schedule.secondary {
    background: transparent;
    color: var(--text-white);
    border: 2px solid var(--accent);
    padding: 0.8rem 1.5rem;
}
.btn-schedule.secondary:hover {
    background: var(--accent);
    color: var(--navy);
    box-shadow: none;
}

/* Direct contact */
.contact-section { max-width: 720px; margin: 5rem auto 4rem; padding: 0 2rem; }
.contact-card {
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2.5rem;
    background: var(--navy-card);
    position: relative;
    overflow: hidden;
}
.contact-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: var(--rainbow);
    background-size: 200% 100%;
    animation: prideShimmer 4s linear infinite;
}
.contact-card h2 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.6rem;
    font-weight: 800;
    margin-bottom: 0.5rem;
    text-align: center;
}
.contact-card .subtitle {
    text-align: center;
    font-family: 'Montserrat', Arial, sans-serif;
    color: var(--text-soft);
    font-size: 0.95rem;
    margin-bottom: 2rem;
}

.form-row { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; margin-bottom: 1rem; }
.form-row.full { grid-template-columns: 1fr; }
@media (max-width: 500px) { .form-row { grid-template-columns: 1fr; } }
.form-group { display: flex; flex-direction: column; }
.form-group label {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    color: var(--accent);
    margin-bottom: 0.4rem;
    font-weight: 700;
}
.form-group input,
.form-group select,
.form-group textarea {
    background: rgba(255,255,255,0.06);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 0.85rem 1rem;
    color: var(--text-white);
    font-size: 1rem;
    font-family: 'Roboto Slab', Georgia, serif;
    transition: var(--transition);
}
.form-group select { appearance: none; background-image: linear-gradient(45deg, transparent 50%, var(--accent) 50%), linear-gradient(135deg, var(--accent) 50%, transparent 50%); background-position: calc(100% - 18px) center, calc(100% - 13px) center; background-size: 5px 5px, 5px 5px; background-repeat: no-repeat; padding-right: 2.5rem; }
.form-group select option { background: var(--navy-deep); color: var(--text-white); }
.form-group textarea { resize: vertical; min-height: 130px; font-family: 'Roboto Slab', Georgia, serif; }
.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
    outline: none;
    border-color: var(--accent);
    background: rgba(115,215,238,0.05);
}
.form-group input::placeholder, .form-group textarea::placeholder { color: rgba(255,255,255,0.25); }

.btn-submit {
    background: var(--action-blue);
    color: #ffffff;
    width: 100%;
    margin-top: 0.75rem;
    font-size: 1rem;
    padding: 1.05rem;
    border-radius: 8px;
    font-family: 'Montserrat', Arial, sans-serif;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1.5px;
    border: none;
    cursor: pointer;
    transition: var(--transition);
}
.btn-submit:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 30px rgba(0,77,255,0.4);
    background: #0040d9;
}
.btn-submit:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.success-message { display: none; text-align: center; padding: 2rem 0; }
.success-message .check {
    font-size: 3.5rem;
    margin-bottom: 1rem;
    color: var(--accent);
}
.success-message h3 {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 1.4rem;
    margin-bottom: 0.75rem;
    font-weight: 800;
}
.success-message p { color: var(--text-soft); line-height: 1.7; }

/* Direct contact strip */
.direct-strip {
    max-width: 1100px;
    margin: 0 auto 5rem;
    padding: 0 2rem;
}
.direct-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 1rem;
}
@media (max-width: 720px) { .direct-grid { grid-template-columns: 1fr; } }
.direct-card {
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 1.5rem;
    background: var(--navy-card);
    text-align: center;
    transition: var(--transition);
}
.direct-card:hover { border-color: rgba(115,215,238,0.25); }
.direct-card .icon { font-size: 1.5rem; margin-bottom: 0.5rem; display: block; }
.direct-card .label {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.7rem;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--accent);
    font-weight: 700;
    margin-bottom: 0.4rem;
}
.direct-card .value {
    font-family: 'Montserrat', Arial, sans-serif;
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-white);
    word-break: break-word;
}
.direct-card .value a:hover { color: var(--accent); }

@media (max-width: 768px) {
    .hero { padding: 3.5rem 1.5rem 2rem; }
    .section, .contact-section, .direct-strip { padding-left: 1.5rem; padding-right: 1.5rem; }
    .contact-card { padding: 2rem 1.5rem; }
    .schedule-card { padding: 1.75rem 1.5rem 1.5rem; }
}

